import numpy as np
cimport numpy as np

def gemm(int n):
    cdef int i, j, k
    cdef double trace = 0.0
    cdef double a_ik
    cdef double[:, :] A = np.zeros((n, n), dtype=np.double)
    cdef double[:, :] B = np.zeros((n, n), dtype=np.double)
    cdef double[:, :] C = np.zeros((n, n), dtype=np.double)

    # Initialize A
    for i in range(n):
        for j in range(n):
            A[i, j] = (i + j) % 100 / 10.0

    # Initialize B
    for i in range(n):
        for j in range(n):
            B[i, j] = (i - j + n) % 100 / 10.0

    # Matrix multiply
    for i in range(n):
        for k in range(n):
            a_ik = A[i, k]
            for j in range(n):
                C[i, j] += a_ik * B[k, j]

    # Extract trace
    for i in range(n):
        trace += C[i, i]

    return trace

